ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  id: vars.taskId,
  contextId: vars.contextId,
  kind: "task",
  status: {
    state: "completed",
    message: {
      role: "agent",
      kind: "message",
      messageId: (now() as String) ++ "-" ++ vars.taskId,
      parts: [
        { kind: "text", text: vars.replyText default "" }
      ]
    },
    timestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss'Z'" }
  }
}

%dw 2.0
output application/java
---
[
  { "type": "function", "function": {
      name: "resolve_supplier",
      description: "サプライヤー名/ヒントから ゴールデン ID を解決する",
      parameters: {
        "type": "object",
        properties: {
          supplierName: { "type": "string" },
          hint:         { "type": "string" }
        },
        required: ["supplierName"]
      }
  }},
  { "type": "function", "function": {
      name: "get_supplier_relations",
      description: "ゴールデン ID から親会社・子会社・過去インシデント・代替部品候補を取得",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          depth:            { "type": "integer" }
        },
        required: ["supplierGoldenId"]
      }
  }},
  { "type": "function", "function": {
      name: "list_suppliers",
      description: "条件指定 (region / status / リスクスコア範囲) で取引先一覧を取得 (READ-ONLY)。region 完全一致。 status 既定 ACTIVE。",
      parameters: {
        "type": "object",
        properties: {
          region:       { "type": "string", description: "Region__c の値 (例: 関西、 中部、 兵庫、 関東、 九州、 東北)" },
          status:       { "type": "string", description: "ACTIVE / INACTIVE / BLOCKED / ALL" },
          riskScoreMin: { "type": "number" },
          riskScoreMax: { "type": "number" },
          limit:        { "type": "integer" }
        },
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "list_regions",
      description: "Supplier__c.Region__c の DISTINCT 値と、 各 region の ACTIVE 件数を一覧で返す (READ-ONLY)。",
      parameters: {
        "type": "object",
        properties: {},
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "list_parts",
      description: "条件指定 (supplierGoldenId / category / location / nameLike) で部品一覧を取得 (READ-ONLY)。 既定 limit=10、 上限 50。",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          category:         { "type": "string", description: "電力設備 / 機械部品 / 電子部品 / 素材" },
          location:         { "type": "string" },
          nameLike:         { "type": "string" },
          limit:            { "type": "integer" }
        },
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "resolve_part",
      description: "部品番号 (Name 完全一致) で部品詳細 1 件を取得 (READ-ONLY)。",
      parameters: {
        "type": "object",
        properties: { partNumber: { "type": "string" } },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "list_part_alternatives",
      description: "部品の代替品一覧 (互換スコア降順) を取得 (READ-ONLY)。",
      parameters: {
        "type": "object",
        properties: {
          partNumber: { "type": "string" },
          limit:      { "type": "integer" }
        },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "find_suppliers_for_part",
      description: "部品を供給可能なサプライヤー一覧 (主+代替経由、 RiskScore 昇順) を取得 (READ-ONLY)。",
      parameters: {
        "type": "object",
        properties: {
          partNumber: { "type": "string" },
          limit:      { "type": "integer" }
        },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "list_incidents",
      description: "インシデント一覧を取得 (READ-ONLY、 ORDER BY CreatedDate DESC)。 既定 limit=10、 上限 50。",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          status:           { "type": "string", description: "OPEN / IN_PROGRESS / RESOLVED / ALL" },
          severity:         { "type": "string", description: "CRITICAL / HIGH / MEDIUM / LOW" },
          since:            { "type": "string", description: "ISO8601 日付" },
          limit:            { "type": "integer" }
        },
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "update_supplier_risk_score",
      description: "サプライヤーのリスクスコア (0..1) を更新する",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          riskScore:        { "type": "number" },
          reason:           { "type": "string" },
          incidentId:       { "type": "string" }
        },
        required: ["supplierGoldenId", "riskScore"]
      }
  }},
  { "type": "function", "function": {
      name: "update_ontology",
      description: "KG に subject/predicate/object のトリプルを記録",
      parameters: {
        "type": "object",
        properties: {
          subject:    { "type": "string" },
          predicate:  { "type": "string" },
          "object":   { "type": "string" },
          incidentId: { "type": "string" }
        },
        required: ["subject", "predicate", "object"]
      }
  }},
  { "type": "function", "function": {
      name: "get_quality_agreement",
      description: "サプライヤーの品質保証協定書サマリ (条項・ペナルティ上限) を取得",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" }
        },
        required: ["supplierGoldenId"]
      }
  }},
  { "type": "function", "function": {
      name: "generate_return_request",
      description: "返品要求書を生成する。requestId を返す",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          incidentId:       { "type": "string" },
          quantity:         { "type": "integer" },
          reason:           { "type": "string" }
        },
        required: ["supplierGoldenId", "partNumber", "incidentId"]
      }
  }},
  { "type": "function", "function": {
      name: "send_penalty_notice",
      description: "ペナルティ通知書を送付する。noticeId を返す",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          incidentId:       { "type": "string" },
          amount:           { "type": "number" },
          currency:         { "type": "string" }
        },
        required: ["supplierGoldenId", "incidentId", "amount"]
      }
  }}
]

%dw 2.0
output application/java
fun safeReadJson(s: String) =
  if (s == null or trim(s) == "") {}
  else read(s, "application/json")
---
if (payload == null) {}
else if (payload is Binary) safeReadJson(payload as String { encoding: "UTF-8" })
else if (payload is String) safeReadJson(payload as String)
else payload
